    int rearrangeCharacters(string s, string target) {
        int sCount[26] = {0}, targetCount[26] = {0};
        for (char c : s) sCount[c - 'a']++;
        for (char c : target) targetCount[c - 'a']++;
        int res = INT_MAX;
        for (int i = 0; i < 26; i++) {
            res = min(res, sCount[i] / targetCount[i]);
        }
        return res;
